// --- SUBSTRATE CONFIGURATION ---
const CONFIG_DIR = path.join(os.homedir(), ".config", "llm-agent");
const CONFIG_FILE = path.join(CONFIG_DIR, "config.json");

// Ensure config exists or use defaults
let config = {
